responses.body:
{
  "transaction": {
    "TransactionID": "{{urlParam 'id'}}",
    "PaidByUserID": "{{faker 'string.uuid'}}",
    "Title": "{{faker 'lorem.words' min=2 max=4}}",
    "TotalAmount": {{faker 'number.float' min=10 max=500 fractionDigits=2}},
    "Currency": "USD",
    "Memo": "{{faker 'lorem.sentence'}}",
    "TransactionDate": "{{faker 'date.past'}}",
    "DueDate": "{{faker 'date.future'}}",
    "CreatedAt": "{{faker 'date.past'}}",
    "UpdatedAt": "{{faker 'date.anytime'}}"
  },
  "splits": [
    {{#repeat 2}}
    {
      "SplitID": "{{faker 'string.uuid'}}",
      "TransactionID": "{{urlParam 'id'}}",
      "UserID": "{{faker 'string.uuid'}}",
      "OweAmount": {{faker 'number.float' min=5 max=250 fractionDigits=2}},
      "PaymentStatus": "{{oneOf (array 'Pending' 'Submitted' 'Approved' 'Overdue')}}",
      "PaymentMethod": "Venmo",
      "PayslipURL": "{{faker 'internet.url'}}",
      "ApprovalStatus": "{{oneOf (array 'Pending_Approval' 'Approved' 'Rejected')}}",
      "SettledAt": "{{faker 'date.anytime'}}",
      "UpdatedAt": "{{faker 'date.anytime'}}"
    }
    {{/repeat}}
  ]
}
